        </div>

        <form id="item-form" onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-8 space-y-6 bg-[#FCFBFA]">
          <div>
            <label htmlFor="item-name" className="block text-[13px] font-bold text-stone-500 mb-2 uppercase tracking-widest">Dish Name <span className="text-red-400">*</span></label>
            <input
              id="item-name"
              name="name"
              value={form.name}
              onChange={e => update('name', e.target.value)}
              placeholder="e.g. Saffron Risotto"
              required
              autoFocus
              className="w-full px-5 py-4 border border-stone-200 rounded-[16px] text-[15px] font-bold text-stone-900 placeholder:font-medium placeholder:text-stone-300 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#ea580c] transition-all bg-white shadow-sm"
            />
          </div>

          <div>
            <label className="flex items-center gap-4 cursor-pointer p-5 bg-white border border-stone-200 rounded-[16px] hover:border-[#ea580c] transition-colors w-full shadow-sm">
              <input
                type="checkbox"
                name="isVeg"
                checked={form.isVeg}
                onChange={e => update('isVeg', e.target.checked)}
                className="w-6 h-6 rounded-md border-stone-300 text-emerald-500 focus-visible:ring-2 focus-visible:ring-emerald-500 shrink-0 cursor-pointer"
              />
              <div>
                <span className="text-[15px] font-black tracking-tight text-stone-900 block">Vegetarian Status</span>
                <span className="text-[13px] text-stone-400 font-medium">Is this item completely plant-based or vegetarian?</span>
              </div>
            </label>
          </div>

          <div className="grid grid-cols-2 gap-5">
            <div>
              <label htmlFor="item-price" className="block text-[13px] font-bold text-stone-500 mb-2 uppercase tracking-widest">Pricing (₹) <span className="text-red-400">*</span></label>
              <input
                id="item-price"
                name="price"
                type="number"
                step="0.01"
                min="0"
                value={form.price}
                onChange={e => update('price', e.target.value)}
                placeholder="0.00"
                required
                className="w-full px-5 py-4 border border-stone-200 rounded-[16px] text-[15px] font-bold text-stone-900 placeholder:font-medium placeholder:text-stone-300 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#ea580c] transition-all bg-white tabular-nums shadow-sm"
              />
            </div>

            <div>
              <label htmlFor="item-category" className="block text-[13px] font-bold text-stone-500 mb-2 uppercase tracking-widest">Placement <span className="text-red-400">*</span></label>
              <select
                id="item-category"
                name="categoryId"
                value={form.categoryId}
                onChange={e => update('categoryId', e.target.value)}
                required
                className="w-full px-5 py-4 border border-stone-200 rounded-[16px] text-[15px] font-bold text-stone-900 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#ea580c] transition-all bg-white cursor-pointer shadow-sm"
              >
                <option value="" disabled>Select category</option>
                {categories.map(c => (
                  <option key={c.id} value={c.id}>{c.name}</option>
                ))}
              </select>
            </div>
          </div>

          <div>
            <label htmlFor="item-desc" className="block text-[13px] font-bold text-stone-500 mb-2 uppercase tracking-widest">Flavor Profile (Desc)</label>
            <textarea
              id="item-desc"
              name="description"
              value={form.description}
              onChange={e => update('description', e.target.value)}
              placeholder="Detail the rich textures, sourcing, and flavor notes to entice the customer..."
              rows={3}
              className="w-full px-5 py-4 border border-stone-200 rounded-[16px] text-[15px] font-bold text-stone-900 placeholder:font-medium placeholder:text-stone-300 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#ea580c] transition-all bg-white resize-none shadow-sm leading-relaxed"
            />
          </div>

          <div>
            <label className="block text-[13px] font-bold text-stone-500 mb-2 uppercase tracking-widest">Dish Image (Direct Upload)</label>
            <div className="mt-2 w-full p-6 border-2 border-dashed border-stone-200 rounded-[16px] flex flex-col items-center justify-center bg-stone-50 hover:bg-stone-100 hover:border-[#ea580c] transition-colors relative">
              <input
                type="file"
                accept="image/*"
                onChange={async (e) => {
                  const file = e.target.files?.[0];
                  if (!file) return;

                  setLoading(true);
                  try {
                    const { getSupabase } = await import('@/lib/supabase');
                    const supabase = getSupabase();

                    // 1. Upload to Supabase Storage bucket 'menu-images'
                    const fileExt = file.name.split('.').pop();
                    const fileName = `${Math.random().toString(36).substring(2, 15)}_${Date.now()}.${fileExt}`;

                    const { error: uploadError } = await supabase.storage
                      .from('menu-images')
                      .upload(fileName, file, { cacheControl: '3600', upsert: false });

                    if (uploadError) throw uploadError;

                    // 2. Get Public URL
                    const { data: publicUrlData } = supabase.storage
                      .from('menu-images')
                      .getPublicUrl(fileName);

                    update('imageUrl', publicUrlData.publicUrl);
                  } catch (err: unknown) {
                    const message = err instanceof Error ? err.message : String(err);
                    alert(`Upload failed: ${message}. Ensure you have created a public bucket named 'menu-images' in Supabase.`);
                  } finally {
                    setLoading(false);
                  }
                }}
                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                disabled={loading}
              />

              <svg className="w-8 h-8 text-stone-400 mb-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
              </svg>
              <span className="text-[14px] font-bold text-stone-900 leading-tight">Click or drag image here</span>
              <span className="text-[12px] font-medium text-stone-400 mt-1">Directly uploads to high-speed CDN</span>

              {loading && (
                <div className="absolute inset-0 bg-white/80 backdrop-blur-sm flex items-center justify-center rounded-[14px]">
                  <span className="text-[14px] font-bold text-[#ea580c] animate-pulse">Uploading to Supabase...</span>
                </div>
              )}
            </div>
            {form.imageUrl && (
              <div className="mt-3 flex items-center justify-between bg-emerald-50 text-emerald-700 px-4 py-3 rounded-[12px] border border-emerald-100">
                <span className="text-[12px] font-bold truncate max-w-[300px]">{form.imageUrl}</span>
                <button type="button" onClick={() => update('imageUrl', '')} className="text-[12px] font-bold hover:text-emerald-900 underline">Remove</button>
              </div>
            )}
          </div>
        </form>

        <div className="p-8 border-t border-stone-100 bg-white">
          <Button type="submit" form="item-form" loading={loading} className="w-full !rounded-[16px] !py-4 text-[16px] !bg-stone-900 text-white font-black hover:!bg-[#ea580c] transition-colors duration-300 shadow-[0_8px_30px_rgba(0,0,0,0.12)]">
            {item ? 'Commit Changes' : 'Publish Dish'}
          </Button>
        </div>
      </div>
    </>
  );
}

'use client';

import { useState } from 'react';
import useSWR, { mutate } from 'swr';
import { useAuthFetcher } from '@/hooks/useRealtime';
import { Button } from '@/components/Button';
import { StatusBadge } from '@/components/StatusBadge';
import { Skeleton } from '@/components/Skeleton';

interface Table {
  id: string;
  number: number;
  label: string | null;
  status: string;
  capacity: number;
}

export default function AdminTablesPage() {
  const authFetcher = useAuthFetcher();
  const { data, isLoading } = useSWR('/api/tables', authFetcher);
  const [showForm, setShowForm] = useState(false);
  const [editTable, setEditTable] = useState<Table | null>(null);
  const [qrTableId, setQrTableId] = useState<string | null>(null);
  const [qrSvg, setQrSvg] = useState<string | null>(null);

  const tables: Table[] = data || [];

  const handleDelete = async (id: string) => {
    if (!confirm('Delete this table?')) return;
    const token = localStorage.getItem('auth-token');
    await fetch(`/api/tables/${id}`, {
      method: 'DELETE',
      headers: { Authorization: `Bearer ${token}` },
    });
    mutate('/api/tables');
  };

  const showQR = async (tableId: string) => {
    const token = localStorage.getItem('auth-token');
    const res = await fetch(`/api/tables/${tableId}/qr`, {
      headers: { Authorization: `Bearer ${token}` },
    });
    const d = await res.json();
    if (d.success) {
      setQrSvg(d.data.qrCodeDataUrl);
      setQrTableId(tableId);
    }
  };

  return (
    <div className="p-6 max-w-4xl mx-auto">
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-2xl font-bold text-gray-900">Table Management</h1>
        <Button onClick={() => { setEditTable(null); setShowForm(true); }}>+ Add Table</Button>
      </div>

      {isLoading ? (
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
          {[1, 2, 3, 4, 5, 6].map(i => (
            <Skeleton key={i} className="h-36 w-full rounded-xl" />
          ))}
        </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
          {tables.map(table => (
            <div key={table.id} className="bg-white rounded-xl shadow-sm p-4 flex flex-col">
              <div className="flex items-center justify-between mb-2">
                <span className="text-lg font-bold text-gray-900">Table {table.number}</span>
                <StatusBadge status={table.status} variant="table" />
              </div>
              {table.label && (
                <span className="text-sm text-gray-500 mb-1">{table.label}</span>
              )}
              <span className="text-sm text-gray-400 mb-3">Capacity: {table.capacity}</span>
              <div className="flex gap-1 mt-auto">
                <button
                  onClick={() => showQR(table.id)}
                  className="flex-1 text-xs px-2 py-1.5 min-h-[36px] bg-blue-50 text-blue-600 rounded-lg font-medium cursor-pointer focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-blue-500 focus-visible:ring-offset-1"
                >
                  QR Code
                </button>
                <button
                  onClick={() => { setEditTable(table); setShowForm(true); }}
                  className="flex-1 text-xs px-2 py-1.5 min-h-[36px] bg-gray-100 text-gray-600 rounded-lg font-medium cursor-pointer focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-orange-500 focus-visible:ring-offset-1"
                >
                  Edit
                </button>
                <button
                  onClick={() => handleDelete(table.id)}
                  aria-label={`Delete table ${table.number}`}
                  className="text-xs px-2 py-1.5 min-h-[36px] bg-red-50 text-red-600 rounded-lg font-medium cursor-pointer focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-red-500 focus-visible:ring-offset-1"
                >
                  ✕
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* QR Code Modal */}
      {qrTableId && qrSvg && (
        <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50 p-4" role="dialog" aria-modal="true" aria-labelledby="qr-modal-title">
          <div className="bg-white rounded-xl p-6 text-center max-w-sm w-full">
            <h2 id="qr-modal-title" className="text-lg font-semibold text-gray-900 mb-4">
              Table {tables.find(t => t.id === qrTableId)?.number} QR Code
            </h2>
            <img
              src={qrSvg}
              alt={`QR code for table ${tables.find(t => t.id === qrTableId)?.number}`}
              width={256}
              height={256}
              className="inline-block bg-white p-4 rounded-lg w-64 h-64"
            />
            <p className="text-xs text-gray-400 mt-3 mb-4">Scan to start ordering</p>
            <Button variant="secondary" onClick={() => { setQrTableId(null); setQrSvg(null); }}>
              Close
            </Button>
          </div>
        </div>
      )}

      {/* Form Modal */}
      {showForm && (
        <TableFormModal
          table={editTable}
          onClose={() => { setShowForm(false); setEditTable(null); }}
        />
      )}
    </div>
  );
}

function TableFormModal({ table, onClose }: { table: Table | null; onClose: () => void }) {
  const [number, setNumber] = useState(table?.number || 0);
  const [label, setLabel] = useState(table?.label || '');
  const [capacity, setCapacity] = useState(table?.capacity || 4);
  const [status, setStatus] = useState(table?.status || 'AVAILABLE');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    const token = localStorage.getItem('auth-token');
    const url = table ? `/api/tables/${table.id}` : '/api/tables';
    const method = table ? 'PATCH' : 'POST';

    const res = await fetch(url, {
      method,
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
      body: JSON.stringify({
        number: Number(number),
        label: label || undefined,
        capacity: Number(capacity),
        ...(table ? { status } : {}),
      }),
    });

    const data = await res.json();
    if (!data.success) {
      setError(data.error?.message || 'Failed');
      setLoading(false);
      return;
    }

    mutate('/api/tables');
    setLoading(false);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50 p-4" role="dialog" aria-modal="true" aria-labelledby="table-form-title">
      <form onSubmit={handleSubmit} className="bg-white rounded-xl p-6 w-full max-w-sm space-y-4">
        <h2 id="table-form-title" className="text-lg font-semibold text-gray-900">{table ? 'Edit Table' : 'Add Table'}</h2>

        <div>
          <label htmlFor="tbl-number" className="block text-sm font-medium text-gray-700 mb-1">Table Number</label>
          <input
            id="tbl-number"
            name="number"
            type="number"
            min="1"
            value={number}
            onChange={e => setNumber(Number(e.target.value))}
            placeholder="1"
            required
            className="w-full px-4 py-3 border border-gray-200 rounded-lg text-gray-900 tabular-nums focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-orange-500"
          />
        </div>
        <div>
          <label htmlFor="tbl-label" className="block text-sm font-medium text-gray-700 mb-1">Label</label>
          <input
            id="tbl-label"
            name="label"
            value={label}
            onChange={e => setLabel(e.target.value)}
            placeholder="e.g. Window, Patio\u2026"
            className="w-full px-4 py-3 border border-gray-200 rounded-lg text-gray-900 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-orange-500"
          />
        </div>
        <div>
          <label htmlFor="tbl-capacity" className="block text-sm font-medium text-gray-700 mb-1">Capacity</label>
          <input
            id="tbl-capacity"
            name="capacity"
            type="number"
            min="1"
            value={capacity}
            onChange={e => setCapacity(Number(e.target.value))}
            placeholder="4"
            className="w-full px-4 py-3 border border-gray-200 rounded-lg text-gray-900 tabular-nums focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-orange-500"
          />
        </div>
        {table && (
          <div>
            <label htmlFor="tbl-status" className="block text-sm font-medium text-gray-700 mb-1">Status</label>
            <select
              id="tbl-status"
              name="status"
              value={status}
              onChange={e => setStatus(e.target.value)}
              className="w-full px-4 py-3 border border-gray-200 rounded-lg text-gray-900 cursor-pointer focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-orange-500"
            >
              <option value="AVAILABLE">Available</option>
              <option value="OCCUPIED">Occupied</option>
              <option value="RESERVED">Reserved</option>
              <option value="DISABLED">Disabled</option>
            </select>
          </div>
        )}

        {error && (
          <div role="alert" className="bg-red-50 text-red-700 text-sm p-3 rounded-lg">{error}</div>
        )}

        <div className="flex gap-2">
          <Button type="button" variant="secondary" onClick={onClose} className="flex-1">Cancel</Button>
          <Button type="submit" loading={loading} className="flex-1">
            {table ? 'Update' : 'Create'}
          </Button>
        </div>
      </form>
    </div>
  );
}

'use client';

import useSWR from 'swr';
import Link from 'next/link';
import { swrFetcher } from '@/hooks/useRealtime';
import { formatCurrency, ORDER_STATUS_DISPLAY } from '@/lib/utils';
import { StatusBadge } from '@/components/StatusBadge';
import { OrderCardSkeleton } from '@/components/Skeleton';

interface OrderItem {
    id: string;
    name: string;
    quantity: number;
    price: number;
    notes: string | null;
}

interface Order {
    id: string;
    orderNumber: number;
    status: string;
    subtotal: number;
    taxAmount: number;
    totalAmount: number;
    createdAt: string;
    items: OrderItem[];
    payment: { status: string; method: string } | null;
}

interface SessionData {
    id: string;
    status: string;
    table: { id: string; number: number; label: string | null };
    orders: Order[];
}

function getSessionId(): string | null {
    if (typeof window === 'undefined') return null;
    try {
        const data = localStorage.getItem('qr-dine-session');
        if (!data) return null;
        return JSON.parse(data).sessionId || null;
    } catch {
        return null;
    }
}

export default function MyOrdersPage({ params }: { params: { tableId: string } }) {
    const sessionId = getSessionId();

    const { data: session, isLoading } = useSWR<SessionData>(
        sessionId ? `/api/sessions/${sessionId}` : null,
        swrFetcher,
        { refreshInterval: 10000 }
    );

    const orders = session?.orders || [];
    const activeOrders = orders.filter(o => o.status !== 'CANCELLED');

    const grandSubtotal = activeOrders.reduce((sum, o) => sum + Number(o.subtotal), 0);
    const grandTax = activeOrders.reduce((sum, o) => sum + Number(o.taxAmount), 0);
    const grandTotal = activeOrders.reduce((sum, o) => sum + Number(o.totalAmount), 0);

    if (!sessionId) {
        return (
            <div className="min-h-screen bg-stone-50 flex items-center justify-center p-6">
                <div className="text-center animate-fade-in-up">
                    <div className="text-6xl mb-6 grayscale opacity-80">📋</div>
                    <h2 className="text-2xl font-bold text-stone-900 mb-3 tracking-tight">No active session</h2>
                    <p className="text-stone-500 mb-8 font-medium">Please scan the QR code to start ordering.</p>
                </div>
            </div>
        );
    }

    if (isLoading) {
        return (
            <div className="min-h-screen bg-stone-50">
                <header className="bg-white shadow-sm sticky top-0 z-40">
                    <div className="max-w-lg mx-auto px-5 py-4 flex items-center gap-4 border-b border-stone-100">
                        <Link href={`/table/${params.tableId}/menu`} className="text-stone-400 hover:text-stone-900 transition-colors flex items-center justify-center w-8 h-8 rounded-full hover:bg-stone-100">
                            ←
                        </Link>
                        <h1 className="text-2xl font-bold text-stone-900 tracking-tight">My Orders</h1>
                    </div>
                </header>
                <main className="max-w-lg mx-auto px-5 py-6 space-y-4">
                    {[...Array(3)].map((_, i) => (
                        <OrderCardSkeleton key={i} />
                    ))}
                </main>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-[#FCFBFA] pb-44 font-sans antialiased text-stone-900">
            {/* Header */}
            <header className="bg-white/95 backdrop-blur-md shadow-[0_2px_15px_rgba(0,0,0,0.03)] sticky top-0 z-40 border-b border-stone-100/80">
                <div className="max-w-2xl mx-auto px-5 py-4 flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <Link href={`/table/${params.tableId}/menu`} className="text-stone-400 hover:text-stone-900 transition-colors flex items-center justify-center w-8 h-8 rounded-full hover:bg-stone-50 font-bold active:scale-95">
                            ←
                        </Link>
                        <div>
                            <h1 className="text-2xl font-black tracking-tight text-stone-900">My Orders</h1>
                            <p className="text-[11px] font-bold text-stone-400 mt-0.5 uppercase tracking-widest">
                                Table {session?.table?.number} • {activeOrders.length} Order{activeOrders.length !== 1 ? 's' : ''}
                            </p>
                        </div>
                    </div>
                </div>
            </header>

            <main className="max-w-2xl mx-auto px-5 py-8 space-y-6">
                {orders.length === 0 ? (
                    <div className="text-center py-20 animate-fade-in-up">
                        <div className="text-6xl mb-6 grayscale opacity-80 mix-blend-multiply">🍽️</div>
                        <h2 className="text-[22px] font-black tracking-tight mb-2">No orders yet</h2>
                        <p className="text-[15px] font-medium text-stone-500 mb-8">Your orders will appear here.</p>
                        <Link
                            href={`/table/${params.tableId}/menu`}
                            className="inline-block py-4 px-8 bg-stone-900 text-white rounded-[16px] text-[15px] font-bold hover:bg-stone-800 transition-all active:scale-[0.98] shadow-elegant tracking-wide"
                        >
                            Browse Menu
                        </Link>
                    </div>
                ) : (
                    <>
                        {/* Individual Orders */}
                        {orders.map((order, index) => (
                            <div
                                key={order.id}
                                className={`bg-white rounded-[24px] p-6 shadow-sm border border-stone-100 hover:shadow-[0_8px_30px_rgb(0,0,0,0.04)] transition-shadow animate-fade-in-up ${order.status === 'CANCELLED' ? 'opacity-50 grayscale' : ''
                                    }`}
                                style={{ animationDelay: `${index * 80}ms` }}
                            >
                                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-5 pb-5 border-b border-stone-100/60">
                                    <div>
                                        <h3 className="font-black text-stone-900 text-[19px] tracking-tight">
                                            Order #{order.orderNumber}
                                        </h3>
                                        <p className="text-[12px] uppercase tracking-widest text-stone-400 font-bold mt-1">
                                            {new Date(order.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
